// 1. Create a detached <li> in memory
const newLi = document.createElement('li');

// 2. Modify it
newLi.innerText = 'Buy Groceries';
newLi.classList.add('todo-item');

// 3. Select the parent list and attach the new item
const list = document.querySelector('#todo-list');
list.appendChild(newLi); // Now it appears on screen!

// Modern Alternative: insertAdjacentHTML (Fast and easy for raw HTML strings)
list.insertAdjacentHTML('beforeend', '<li class="todo-item">Walk Dog</li>');
